INSERT INTO public.blog_posts (id, title, slug, excerpt, content, featured_image, category_id, tags, status, author_name, published_at, created_at)
VALUES
  ('73617487-4d29-4344-a639-667d8dccff7c', '10 Must-Know Tips for First-Time International Travelers', '10-tips-first-time-international-travelers', 'Planning your first trip abroad? These essential tips will help you navigate airports, currencies, and cultures like a pro.', '<h2>Traveling Abroad for the First Time?</h2><p>International travel can be both exciting and overwhelming.</p><h3>1. Check Passport Validity</h3><p>Many countries require your passport to be valid for at least 6 months beyond your travel dates.</p><h3>2. Research Visa Requirements</h3><p>Some destinations offer visa-on-arrival, while others require advance applications.</p><h3>3. Get Travel Insurance</h3><p>Medical emergencies abroad can be incredibly expensive.</p><h3>4. Notify Your Bank</h3><p>Let your bank know about your travel plans.</p><h3>5. Pack Light</h3><p>Stick to versatile clothing and leave room for souvenirs.</p><h3>6. Learn Basic Phrases</h3><p>A simple hello and thank you in the local language goes a long way.</p><h3>7. Keep Digital Copies</h3><p>Scan your passport, tickets, and hotel confirmations.</p><h3>8. Stay Connected</h3><p>Consider getting a local SIM card or an international data plan.</p><h3>9. Be Aware of Local Customs</h3><p>Research cultural norms to avoid unintentional faux pas.</p><h3>10. Enjoy the Journey</h3><p>Leave room for spontaneous adventures.</p>', 'https://images.unsplash.com/photo-1488646953014-85cb44e25828?w=800', 'fcfee9c2-1794-4aa5-8bf4-0fa8cb6f7449', '["tips","international","beginners"]', 'published', 'Travel Team', '2026-02-27 09:43:10.905303+00', '2026-03-01 09:43:10.905303+00'),
  ('441524eb-6417-407a-b62d-cef1237bbebf', 'Top 5 Budget-Friendly Destinations for 2026', 'top-5-budget-friendly-destinations-2026', 'Dreaming of a vacation that won''t break the bank? These stunning destinations offer incredible experiences at a fraction of the cost.', '<h2>Travel More, Spend Less</h2><p>You don''t need a massive budget to explore the world.</p><h3>1. Vietnam</h3><p>World-class experiences for under $40/day.</p><h3>2. Portugal</h3><p>Stunning coastlines, rich history, and incredible cuisine at lower prices.</p><h3>3. Colombia</h3><p>One of South America''s hottest destinations.</p><h3>4. Georgia</h3><p>Breathtaking mountain scenery and legendary hospitality.</p><h3>5. Sri Lanka</h3><p>Beaches, temples, tea plantations, and wildlife safaris.</p>', 'https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800', '1994ecc8-0228-4491-9fa7-00d150bd89bc', '["budget","destinations","2026"]', 'published', 'Travel Team', '2026-02-24 09:43:10.905303+00', '2026-03-01 09:43:10.905303+00'),
  ('4d5df5a6-c5a4-4340-815f-61a933028809', 'Exploring the Magic of Santorini: A Travel Diary', 'exploring-magic-of-santorini', 'White-washed buildings, stunning sunsets, and crystal-clear waters — discover why Santorini remains one of the world''s most enchanting destinations.', '<h2>A Week in Paradise</h2><p>Santorini has been on my bucket list for years, and it did not disappoint.</p><h3>Day 1-2: Oia</h3><p>Famous for its blue-domed churches and spectacular sunsets.</p><h3>Day 3-4: Fira & Hiking</h3><p>The hike from Fira to Oia offers panoramic views.</p><h3>Day 5: Beach Day</h3><p>Red Beach with its dramatic crimson cliffs.</p><h3>Day 6-7: Food & Culture</h3><p>Fresh seafood and Assyrtiko wine from local vineyards.</p>', 'https://images.unsplash.com/photo-1613395877344-13d4a8e0d49e?w=800', '6d5340c9-e7dc-45c6-aa19-39688f54a566', '["santorini","greece","destinations","diary"]', 'published', 'Sarah Mitchell', '2026-02-26 09:43:10.905303+00', '2026-03-01 09:43:10.905303+00'),
  ('c33a33f7-5562-40c4-8d1f-f389c2e99562', 'The Ultimate Dubai Travel Guide for 2026', 'ultimate-dubai-travel-guide-2026', 'From towering skyscrapers to ancient souks, Dubai blends tradition and futurism like no other city.', '<h2>Welcome to the City of the Future</h2><p>Dubai is a city that defies expectations at every turn.</p><h3>Must-See Attractions</h3><p>Burj Khalifa, Dubai Mall, Old Dubai.</p><h3>Best Time to Visit</h3><p>November to March offers the most pleasant weather.</p><h3>Getting Around</h3><p>The Dubai Metro is clean, efficient, and affordable.</p><h3>Food Scene</h3><p>Dubai''s dining scene is world-class.</p>', 'https://images.unsplash.com/photo-1512453979798-5ea266f8880c?w=800', '6d5340c9-e7dc-45c6-aa19-39688f54a566', '["dubai","guide","destinations"]', 'published', 'Travel Team', '2026-02-22 09:43:10.905303+00', '2026-03-01 09:43:10.905303+00'),
  ('1c6ffa04-248a-4732-97e4-57ef4cb3f0e5', 'How to Find the Cheapest Flights: A Complete Guide', 'how-to-find-cheapest-flights-guide', 'Unlock the secrets to scoring the best flight deals with these proven strategies.', '<h2>Stop Overpaying for Flights</h2><p>Flight prices can vary dramatically depending on when and how you book.</p><h3>Be Flexible with Dates</h3><p>Flying mid-week is often significantly cheaper.</p><h3>Book at the Right Time</h3><p>For domestic flights, booking 1-3 months in advance typically yields the best prices.</p><h3>Use Incognito Mode</h3><p>Airlines and booking sites may track your searches.</p><h3>Consider Nearby Airports</h3><p>Flying into a secondary airport can save you hundreds.</p><h3>Set Price Alerts</h3><p>Use fare tracking tools to monitor prices.</p>', 'https://images.unsplash.com/photo-1436491865332-7a61a109db05?w=800', '9ed6ef1d-b5e1-4b2a-8eb1-6a113d2bc08f', '["flights","deals","tips"]', 'published', 'Travel Team', '2026-03-01 10:05:15.176+00', '2026-03-01 09:43:10.905303+00')
